/**
 * SPEC-020: Capturas — Dialog "Nueva captura" (componente aislado).
 * SPEC-032: Nombre por defecto de captura con fecha y hora (título opcional).
 * Generated by QA Dev agent.
 *
 * El Dialog no toca el bridge: valida inline y delega en onSubmit, así que la
 * frontera de mocking es la prop onSubmit. Necesita MemoryRouter por el link
 * "Crear discovery" del aviso sin discoveries.
 *
 * Derogación SPEC-032 sobre SPEC-020: el Título deja de ser requerido (vacío o
 * en blanco → nombre por defecto «Captura dd-mmmm-yyyy hh:mm»), así que el test
 * original de AC-10 de SPEC-020 («Campo requerido» bajo el Título) se retira y
 * el de AC-09 se adapta (placeholder con el nuevo formato, Título opcional).
 * La obligatoriedad del Discovery (SPEC-020 AC-11) sigue vigente.
 *
 * Fake timers restringidos a Date (lección 12): vi.useFakeTimers({ toFake:
 * ['Date'] }) congela solo el reloj, sin romper userEvent ni waitFor.
 */
import { render, screen, waitFor, type RenderResult } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest'
import { MemoryRouter } from 'react-router-dom'
import { NewCaptureDialog } from '@/components/captures/NewCaptureDialog'
import type { NewCaptureValues } from '@/hooks/useCaptures'
import type { Discovery, InterviewTemplate } from '@/types/domain'

const DISCOVERY: Discovery = {
  id: 'd-1',
  name: 'Vertical Sanidad',
  objectives: null,
  createdAt: '2026-07-01T09:00:00.000Z',
  updatedAt: '2026-07-01T09:00:00.000Z'
}

const TEMPLATE: InterviewTemplate = {
  id: 'tpl-1',
  name: 'Entrevista MDR',
  phase: 'problem',
  blocks: [{ title: 'Contexto', questions: [{ text: '¿Quién lleva el regulatorio?' }] }],
  createdAt: '2026-07-04T09:00:00.000Z',
  updatedAt: '2026-07-04T09:00:00.000Z'
}

let onSubmit: ReturnType<typeof vi.fn<(values: NewCaptureValues) => Promise<boolean>>>

function renderDialog(options: { discoveries?: Discovery[] } = {}): RenderResult {
  const { discoveries = [DISCOVERY] } = options
  return render(
    <MemoryRouter>
      <NewCaptureDialog
        open
        onOpenChange={vi.fn()}
        discoveries={discoveries}
        templates={[TEMPLATE]}
        onSubmit={onSubmit}
      />
    </MemoryRouter>
  )
}

async function pickDiscovery(user: ReturnType<typeof userEvent.setup>): Promise<void> {
  await user.click(screen.getByRole('combobox', { name: 'Discovery' }))
  await user.click(await screen.findByRole('option', { name: 'Vertical Sanidad' }))
  // Nota: Radix Select emite un warning benigno "update to SelectItem was not
  // wrapped in act" al cerrar; es el mismo ruido preexistente de la suite de
  // CapturesPage (no hay assertion pendiente que dependa de ese update).
}

/** Espera a que el submit asiente (promise de onSubmit resuelta dentro de act). */
async function waitForSubmitSettled(): Promise<void> {
  await waitFor(() => expect(screen.getByRole('button', { name: 'Crear' })).toBeEnabled())
}

beforeEach(() => {
  vi.clearAllMocks()
  onSubmit = vi.fn<(values: NewCaptureValues) => Promise<boolean>>().mockResolvedValue(true)
})

describe('NewCaptureDialog', () => {
  // SPEC-020 · AC-09 — adaptado por SPEC-032: el Título pasa a ser opcional y
  // su placeholder anuncia el nombre por defecto «Captura dd-mmmm-yyyy hh:mm»
  // (el valor exacto del placeholder se asserta con reloj congelado en el
  // describe de SPEC-032, AC-06).
  it('renders Título (optional, with the default-name placeholder), Discovery (required) and Plantilla defaulting to "Sin template" with name+phase labels', async () => {
    const user = userEvent.setup()
    renderDialog()

    expect(screen.getByRole('heading', { name: 'Nueva captura' })).toBeInTheDocument()
    // Título con el placeholder "Captura dd-mmmm-yyyy hh:mm" (mes es-ES en
    // minúsculas, hora local 24 h) calculado con la fecha/hora actuales
    expect(screen.getByLabelText('Título')).toHaveAttribute(
      'placeholder',
      expect.stringMatching(/^Captura \d{2}-[a-zñáéíóú]+-\d{4} \d{2}:\d{2}$/)
    )
    // Discovery requerido, con su placeholder hasta elegir
    expect(screen.getByRole('combobox', { name: 'Discovery' })).toHaveTextContent(
      'Selecciona un discovery'
    )
    // Plantilla opcional: default "Sin template" + etiqueta nombre (fase)
    const templateSelect = screen.getByRole('combobox', { name: 'Plantilla' })
    expect(templateSelect).toHaveTextContent('Sin template')
    await user.click(templateSelect)
    expect(await screen.findByRole('option', { name: 'Sin template' })).toBeInTheDocument()
    expect(screen.getByRole('option', { name: 'Entrevista MDR (Problema)' })).toBeInTheDocument()
  })

  // SPEC-020 · AC-10 — DEROGADO por SPEC-032: el título vacío ya no muestra
  // «Campo requerido» ni bloquea; crea con el nombre por defecto (ver el
  // describe "default capture title (SPEC-032)", AC-01).

  // SPEC-020 · AC-11 (vigente) · co-cobertura SPEC-032 AC-05
  it('shows the inline "Campo requerido" error under Discovery and creates nothing when no discovery is selected', async () => {
    const user = userEvent.setup()
    renderDialog()

    await user.type(screen.getByLabelText('Título'), 'Captura de prueba')
    await user.click(screen.getByRole('button', { name: 'Crear' }))

    expect(await screen.findByText('Campo requerido')).toBeInTheDocument()
    expect(onSubmit).not.toHaveBeenCalled()
  })

  // SPEC-020 · AC-12
  it('disables the Discovery select with "No hay discoveries" and links to create one when there are zero discoveries', () => {
    renderDialog({ discoveries: [] })

    const discoverySelect = screen.getByRole('combobox', { name: 'Discovery' })
    expect(discoverySelect).toBeDisabled()
    expect(discoverySelect).toHaveTextContent('No hay discoveries')
    // Aviso con link que navega a /discoveries
    expect(screen.getByText(/No hay discoveries\./)).toBeInTheDocument()
    expect(screen.getByRole('link', { name: 'Crear discovery' })).toHaveAttribute(
      'href',
      '/discoveries'
    )
  })

  describe('default capture title (SPEC-032)', () => {
    beforeEach(() => {
      vi.useFakeTimers({ toFake: ['Date'] })
    })

    afterEach(() => {
      vi.useRealTimers()
    })

    // SPEC-032 · AC-01
    it('creates the capture with the default title "Captura dd-mmmm-yyyy hh:mm" of the creation moment when Título is left empty', async () => {
      vi.setSystemTime(new Date(2026, 6, 12, 9, 41))
      const user = userEvent.setup()
      renderDialog()

      await pickDiscovery(user)
      await user.click(screen.getByRole('button', { name: 'Crear' }))

      await waitFor(() => expect(onSubmit).toHaveBeenCalledTimes(1))
      expect(onSubmit).toHaveBeenCalledWith({
        title: 'Captura 12-julio-2026 09:41',
        discoveryId: 'd-1',
        templateId: null
      })
      // Sin error: el título vacío ya no bloquea (derogación SPEC-020 AC-10)
      expect(screen.queryByText('Campo requerido')).not.toBeInTheDocument()
      await waitForSubmitSettled()
    })

    // SPEC-032 · AC-02 (mes distinto de AC-01 para fijar el formateador)
    it('creates with the default title when the title has only whitespace, behaving like empty', async () => {
      vi.setSystemTime(new Date(2026, 0, 3, 22, 5))
      const user = userEvent.setup()
      renderDialog()

      await user.type(screen.getByLabelText('Título'), '   ')
      await pickDiscovery(user)
      await user.click(screen.getByRole('button', { name: 'Crear' }))

      await waitFor(() => expect(onSubmit).toHaveBeenCalledTimes(1))
      expect(onSubmit).toHaveBeenCalledWith({
        title: 'Captura 03-enero-2026 22:05',
        discoveryId: 'd-1',
        templateId: null
      })
      expect(screen.queryByText('Campo requerido')).not.toBeInTheDocument()
      await waitForSubmitSettled()
    })

    // SPEC-032 · AC-03: ceros iniciales en día y hora, mes completo en español
    // en minúsculas y hora local 24 h (15:30, nunca 3:30 PM)
    it('formats the default title with zero-padded day and hour, the full lowercase Spanish month and 24h local time', async () => {
      vi.setSystemTime(new Date(2026, 2, 5, 8, 7))
      const user = userEvent.setup()
      renderDialog()

      await pickDiscovery(user)
      const crear = screen.getByRole('button', { name: 'Crear' })
      await user.click(crear)

      await waitFor(() => expect(onSubmit).toHaveBeenCalledTimes(1))
      // dd y hh:mm con cero inicial, mes "marzo" en minúsculas
      expect(onSubmit).toHaveBeenLastCalledWith(
        expect.objectContaining({ title: 'Captura 05-marzo-2026 08:07' })
      )

      // Segunda creación por la tarde: formato 24 h sin meridiano
      vi.setSystemTime(new Date(2026, 11, 31, 15, 30))
      await user.click(crear)

      await waitFor(() => expect(onSubmit).toHaveBeenCalledTimes(2))
      expect(onSubmit).toHaveBeenLastCalledWith(
        expect.objectContaining({ title: 'Captura 31-diciembre-2026 15:30' })
      )
      const lastTitle = (onSubmit.mock.calls[1][0] as NewCaptureValues).title
      expect(lastTitle).not.toMatch(/[ap]\.?\s?m\.?|AM|PM/i)
      await waitForSubmitSettled()
    })

    // SPEC-032 · AC-04
    it('creates with the literal typed title trimmed of surrounding whitespace, as before', async () => {
      vi.setSystemTime(new Date(2026, 6, 12, 9, 41))
      const user = userEvent.setup()
      renderDialog()

      await user.type(screen.getByLabelText('Título'), '  Kickoff con Acme  ')
      await pickDiscovery(user)
      await user.click(screen.getByRole('button', { name: 'Crear' }))

      await waitFor(() => expect(onSubmit).toHaveBeenCalledTimes(1))
      expect(onSubmit).toHaveBeenCalledWith({
        title: 'Kickoff con Acme',
        discoveryId: 'd-1',
        templateId: null
      })
      await waitForSubmitSettled()
    })

    // SPEC-032 · AC-05: el Discovery sigue siendo requerido aunque el título
    // vacío ya no bloquee (un solo error, el del Discovery)
    it('shows "Campo requerido" only under Discovery and creates nothing when no discovery is selected even with the title empty', async () => {
      vi.setSystemTime(new Date(2026, 6, 12, 9, 41))
      const user = userEvent.setup()
      renderDialog()

      await user.click(screen.getByRole('button', { name: 'Crear' }))

      // Un único error inline: el del Discovery (bajo el Título ya no existe)
      expect(await screen.findAllByText('Campo requerido')).toHaveLength(1)
      expect(screen.getByRole('combobox', { name: 'Discovery' })).toHaveAttribute(
        'aria-invalid',
        'true'
      )
      expect(onSubmit).not.toHaveBeenCalled()
    })

    // SPEC-032 · AC-06
    it('shows the Título placeholder announcing the default name for the current date and time', () => {
      vi.setSystemTime(new Date(2026, 6, 12, 9, 41))
      renderDialog()

      expect(screen.getByLabelText('Título')).toHaveAttribute(
        'placeholder',
        'Captura 12-julio-2026 09:41'
      )
    })
  })
})
